 +	// Sanity check: MaxInt64 itself should NOT panic
 +	func() {
 +		defer func() {
 +			if r := recover(); r != nil {
 +				t.Errorf("MustParse(MaxInt64) panicked unexpectedly: %v", r)
 +			}
 +		}()
 +		_ = MustParse("9223372036854775807")
 +	}()
 +}",
